import { useEffect, useState, useCallback, useRef } from 'react'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Textarea } from '@/components/ui/textarea'
import { Dialog, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog'
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs'
import {
  Brain, Target, Lightbulb, MessageSquare, Trophy, TrendingUp,
  Flame, BookOpen, CheckCircle, ArrowRight, Sparkles, BarChart3,
  Clock, Star, Zap, Video, VideoOff, Mic, MicOff, Camera, Eye,
  Volume2, AlertCircle, ChevronDown, ChevronUp, Play, Square,
  Timer, User, Monitor,
} from 'lucide-react'

// Types
interface PracticeQuestion {
  id: string
  category: string
  difficulty: string
  question: string
  key_points: string[]
  times_practiced: number
  last_score: number | null
  avg_score: number | null
  last_practiced: string | null
}

interface PracticeStats {
  total_questions: number
  average_score: number | null
  improvement: number | null
  day_streak: number
  last_practice: string | null
}

interface CategoryScoreDetail {
  score: number
  feedback: string
}

interface VideoCoaching {
  overall_score: number
  content: {
    score: number
    strengths: string[]
    improvements: string[]
    covered_points: string[]
    missed_points: string[]
    detailed_feedback: string
    improved_response: string
    specific_tips: string[]
    common_mistake: string
    practice_prompt: string
  }
  communication: {
    score: number
    word_count: number
    words_per_minute: number
    duration_seconds: number
    filler_words: Record<string, number>
    total_fillers: number
    filler_rate: number
    pace: { assessment: string; wpm: number; feedback: string }
    tips: string[]
  }
  presentation: {
    score: number
    eye_contact: CategoryScoreDetail
    facial_expressions: CategoryScoreDetail
    body_language: CategoryScoreDetail
    professional_appearance: CategoryScoreDetail
    summary: string
    timestamped_notes: { frame: number; note: string }[]
  }
}

// Legacy text coaching (kept for fallback)
interface TextCoaching {
  score: number
  strengths: string[]
  improvements: string[]
  specific_tips?: string[]
  improved_response?: string
  common_mistake?: string
  body_language_tips?: string[]
  practice_prompt?: string
}

interface CategoryProgress {
  category: string
  count: number
  average_score: number
}

interface RecentSession {
  question: string
  category: string
  score: number
  improvements: string[]
  created_at: string
}

const categoryConfig: Record<string, { label: string; icon: React.ElementType; color: string; bg: string }> = {
  behavioral: { label: 'Behavioral', icon: Brain, color: 'text-violet-700', bg: 'bg-violet-100' },
  technical: { label: 'Technical', icon: Zap, color: 'text-rose-700', bg: 'bg-rose-100' },
  situational: { label: 'Situational', icon: Lightbulb, color: 'text-sky-700', bg: 'bg-sky-100' },
}

const difficultyColors: Record<string, string> = {
  Easy: 'bg-green-100 text-green-700',
  Medium: 'bg-amber-100 text-amber-700',
  Hard: 'bg-red-100 text-red-700',
}

// Score color helper
function scoreColor(score: number): string {
  if (score >= 8) return 'text-green-600'
  if (score >= 6) return 'text-amber-600'
  return 'text-red-600'
}

function scoreBg(score: number): string {
  if (score >= 8) return 'bg-green-50 border-green-200'
  if (score >= 6) return 'bg-amber-50 border-amber-200'
  return 'bg-red-50 border-red-200'
}

function scoreLabel(score: number): string {
  if (score >= 9) return 'Excellent'
  if (score >= 8) return 'Great'
  if (score >= 7) return 'Good'
  if (score >= 6) return 'Decent'
  if (score >= 5) return 'Average'
  return 'Needs Work'
}

// Score bar component
function ScoreBar({ score, label, icon: Icon }: { score: number; label: string; icon: React.ElementType }) {
  const pct = (score / 10) * 100
  const barColor = score >= 8 ? 'bg-green-500' : score >= 6 ? 'bg-amber-500' : 'bg-red-500'

  return (
    <div className="space-y-1">
      <div className="flex items-center justify-between text-sm">
        <span className="flex items-center gap-1.5 font-medium">
          <Icon className="h-3.5 w-3.5 text-muted-foreground" />
          {label}
        </span>
        <span className={`font-bold ${scoreColor(score)}`}>{score}/10</span>
      </div>
      <div className="h-2 bg-muted rounded-full overflow-hidden">
        <div className={`h-full ${barColor} rounded-full transition-all duration-700`} style={{ width: `${pct}%` }} />
      </div>
    </div>
  )
}

export function AiCoachingPage() {
  const [tab, setTab] = useState('practice')
  const [stats, setStats] = useState<PracticeStats | null>(null)
  const [questions, setQuestions] = useState<PracticeQuestion[]>([])
  const [categoryFilter, setCategoryFilter] = useState('all')
  const [loading, setLoading] = useState(true)

  // Practice modal state
  const [practiceQuestion, setPracticeQuestion] = useState<PracticeQuestion | null>(null)
  const [responseMode, setResponseMode] = useState<'select' | 'video' | 'text'>('select')
  const [responseText, setResponseText] = useState('')
  const [submitting, setSubmitting] = useState(false)
  const [coaching, setCoaching] = useState<VideoCoaching | null>(null)
  const [textCoaching, setTextCoaching] = useState<TextCoaching | null>(null)

  // Video recording state
  const [isRecording, setIsRecording] = useState(false)
  const [recordingTime, setRecordingTime] = useState(0)
  const [cameraReady, setCameraReady] = useState(false)
  const [cameraError, setCameraError] = useState<string | null>(null)
  const [transcription, setTranscription] = useState('')
  const [isTranscribing, setIsTranscribing] = useState(false)
  const [capturedFrames, setCapturedFrames] = useState<string[]>([])
  const [recordingDone, setRecordingDone] = useState(false)
  const [countdown, setCountdown] = useState<number | null>(null)
  const [cameraStatus, setCameraStatus] = useState('')

  // Refs
  const videoRef = useRef<HTMLVideoElement>(null)
  const mediaRecorderRef = useRef<MediaRecorder | null>(null)
  const streamRef = useRef<MediaStream | null>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const frameIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const recognitionRef = useRef<any>(null)

  // Feedback detail sections
  const [expandedSection, setExpandedSection] = useState<string | null>('content')

  // Progress state
  const [categoryProgress, setCategoryProgress] = useState<CategoryProgress[]>([])
  const [recentSessions, setRecentSessions] = useState<RecentSession[]>([])

  const loadStats = useCallback(async () => {
    try {
      const res = await apiCall<{ success: boolean; stats: PracticeStats }>('/interviews/practice/stats')
      if (res.success) setStats(res.stats)
    } catch (err) {
      console.error('Failed to load stats:', err)
    }
  }, [])

  const loadQuestions = useCallback(async () => {
    try {
      const res = await apiCall<{ success: boolean; questions: PracticeQuestion[] }>('/interviews/practice/library')
      if (res.success) setQuestions(res.questions)
    } catch (err) {
      console.error('Failed to load questions:', err)
    }
  }, [])

  const loadProgress = useCallback(async () => {
    try {
      const res = await apiCall<{
        success: boolean
        progress: { by_category: CategoryProgress[]; recent_sessions: RecentSession[] }
      }>('/interviews/practice/progress')
      if (res.success) {
        setCategoryProgress(res.progress.by_category)
        setRecentSessions(res.progress.recent_sessions)
      }
    } catch (err) {
      console.error('Failed to load progress:', err)
    }
  }, [])

  useEffect(() => {
    async function init() {
      setLoading(true)
      await Promise.all([loadStats(), loadQuestions(), loadProgress()])
      setLoading(false)
    }
    init()
  }, [loadStats, loadQuestions, loadProgress])

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      stopCamera()
      if (timerRef.current) clearInterval(timerRef.current)
      if (frameIntervalRef.current) clearInterval(frameIntervalRef.current)
    }
  }, [])

  function openPractice(q: PracticeQuestion) {
    setPracticeQuestion(q)
    setResponseMode('select')
    setResponseText('')
    setCoaching(null)
    setTextCoaching(null)
    setSubmitting(false)
    setRecordingDone(false)
    setTranscription('')
    setCapturedFrames([])
    setRecordingTime(0)
    setCameraError(null)
    setExpandedSection('content')
  }

  function closePractice() {
    stopCamera()
    stopRecording()
    setPracticeQuestion(null)
    setResponseMode('select')
    setResponseText('')
    setCoaching(null)
    setTextCoaching(null)
    setSubmitting(false)
    setRecordingDone(false)
    setTranscription('')
    setCapturedFrames([])
    setRecordingTime(0)
    setCameraError(null)
    setCountdown(null)
  }

  // Detect iOS (all browsers on iOS use WebKit)
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) ||
    (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1)
  const isChromeIOS = isIOS && /CriOS/.test(navigator.userAgent)
  const isSafari = isIOS && !isChromeIOS && /Safari/.test(navigator.userAgent)

  // Camera management — cross-browser implementation following Google Meet / HireVue patterns.
  //
  // CRITICAL: getUserMedia() MUST be the FIRST async call after the user gesture.
  // On iOS (all browsers use WebKit), inserting ANY await before getUserMedia
  // (e.g., Permissions API query) can expire the user gesture activation,
  // causing iOS to block the camera with NotAllowedError WITHOUT ever showing
  // the permission prompt. This was the root cause of the "never asked" bug.
  //
  // Pattern: User taps → getUserMedia() immediately → handle result.
  // NO Permissions API pre-check. NO async delays. NO retry loops.

  // 7th FIX — Direct <video> in JSX with NO overflow context ancestors.
  //
  // Root cause of 6 failed attempts:
  // 1) Attempts 1-4: <video> inside Dialog's overflow-y:auto + rounded-lg triggers
  //    WebKit compositor bug — video frames never composited.
  // 2) Attempt 5 (canvas): Canvas inside same overflow context — same bug.
  // 3) Attempt 6 (detached video at body + canvas): Detached video was 1x1 px with
  //    opacity:0.01 — iOS WebKit power-saves by skipping frame decoding for
  //    near-invisible video elements. canvas.drawImage() got black frames.
  //    Also, canvas diagnostic text was hidden under the !cameraReady overlay
  //    (z-10 bg-black/90), so user never saw debug info.
  //
  // This fix:
  // - Direct <video> element in JSX (no canvas, no detached elements)
  // - Camera container uses clip-path for rounded corners (NOT overflow-hidden)
  // - Camera sits OUTSIDE all overflow-y scroll containers
  // - Dialog gets overflow-visible override
  // - DOM-based status indicator (always visible, not canvas-drawn)
  // - Force GPU compositing with translateZ(0) on video

  async function startCamera() {
    try {
      setCameraError(null)
      setCameraStatus('Requesting camera...')

      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setCameraError('not_supported')
        setCameraStatus('Not supported')
        return
      }

      // getUserMedia MUST be the FIRST async call after user gesture (iOS requirement)
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { width: { ideal: 640 }, height: { ideal: 480 }, facingMode: 'user' },
        audio: true,
      })

      streamRef.current = stream
      setCameraStatus('Stream acquired')

      const videoTrack = stream.getVideoTracks()[0]
      if (!videoTrack || videoTrack.readyState !== 'live') {
        console.error('[camera] no live video track in stream')
        setCameraError('not_found')
        setCameraStatus('No live track')
        return
      }

      setCameraStatus(`Track live: ${videoTrack.label}`)

      // Attach stream to the <video> element in JSX (ref-based)
      const video = videoRef.current
      if (!video) {
        console.error('[camera] video ref not available')
        setCameraError('unknown')
        setCameraStatus('No video element')
        return
      }

      video.srcObject = stream

      // Play — on iOS the autoPlay attribute can be unreliable after getUserMedia
      // consumed the user gesture, so we explicitly call play()
      try {
        await video.play()
        setCameraStatus('Playing')
      } catch (playErr: any) {
        console.warn('[camera] play() failed, retrying:', playErr?.message)
        setCameraStatus(`Play failed: ${playErr?.message}`)
        await new Promise(r => setTimeout(r, 500))
        try {
          await video.play()
          setCameraStatus('Playing (retry)')
        } catch (retryErr: any) {
          console.warn('[camera] retry play() failed:', retryErr?.message)
          setCameraStatus(`Retry failed: ${retryErr?.message}`)
          // autoPlay + muted + playsInline should eventually start; don't error out
        }
      }

      // Wait for actual frame data — poll readyState
      const waitStart = Date.now()
      const checkReady = () => {
        const v = videoRef.current
        if (!v) return

        const elapsed = Date.now() - waitStart
        if (v.readyState >= 2 && v.videoWidth > 0) {
          // Video is decoding frames
          console.log(`[camera] ready after ${elapsed}ms — ${v.videoWidth}x${v.videoHeight}`)
          setCameraStatus(`OK ${v.videoWidth}x${v.videoHeight}`)
          setCameraReady(true)
          return
        }

        setCameraStatus(`Waiting... readyState=${v.readyState} ${Math.round(elapsed / 1000)}s`)

        if (elapsed > 8000) {
          // Safety: force ready after 8s so user isn't stuck forever
          console.warn('[camera] forcing ready after 8s timeout')
          setCameraStatus(`Timeout — readyState=${v.readyState}`)
          setCameraReady(true)
          return
        }

        setTimeout(checkReady, 200)
      }
      setTimeout(checkReady, 100)

      // Monitor track ending (user revokes permission)
      videoTrack.addEventListener('ended', () => {
        console.warn('[camera] video track ended')
        setCameraReady(false)
        setCameraError('denied')
        setCameraStatus('Track ended')
      })
    } catch (err: any) {
      console.error('Camera access error:', err?.name, err?.message)
      setCameraStatus(`Error: ${err?.name}`)

      if (err.name === 'NotAllowedError') {
        setCameraError('denied')
      } else if (err.name === 'NotFoundError') {
        setCameraError('not_found')
      } else if (err.name === 'OverconstrainedError' || err.name === 'NotReadableError') {
        try {
          const fallbackStream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true })
          streamRef.current = fallbackStream
          setCameraStatus('Fallback stream acquired')
          const video = videoRef.current
          if (video) {
            video.srcObject = fallbackStream
            try { await video.play() } catch {}
            setCameraReady(true)
            setCameraStatus('Fallback OK')
          }
          return
        } catch (fallbackErr: any) {
          setCameraStatus(`Fallback error: ${fallbackErr?.name}`)
          if (fallbackErr.name === 'NotAllowedError') {
            setCameraError('denied')
          } else if (fallbackErr.name === 'NotReadableError') {
            setCameraError('in_use')
          } else {
            setCameraError('unknown')
          }
        }
      } else {
        setCameraError('unknown')
      }
    }
  }

  function stopCamera() {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop())
      streamRef.current = null
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null
    }
    setCameraReady(false)
    setCameraStatus('')
  }

  // Frame capture
  function captureFrame(): string | null {
    if (!videoRef.current || !canvasRef.current) return null
    const canvas = canvasRef.current
    const video = videoRef.current
    canvas.width = 320
    canvas.height = 240
    const ctx = canvas.getContext('2d')
    if (!ctx) return null
    ctx.drawImage(video, 0, 0, 320, 240)
    return canvas.toDataURL('image/jpeg', 0.7)
  }

  // Speech Recognition
  function startSpeechRecognition() {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition
    if (!SpeechRecognition) {
      console.warn('Speech recognition not supported')
      return
    }

    const recognition = new SpeechRecognition()
    recognition.continuous = true
    recognition.interimResults = true
    recognition.lang = 'en-US'

    let finalTranscript = ''

    recognition.onresult = (event: any) => {
      let interim = ''
      for (let i = event.resultIndex; i < event.results.length; i++) {
        const result = event.results[i]
        if (result.isFinal) {
          finalTranscript += result[0].transcript + ' '
        } else {
          interim = result[0].transcript
        }
      }
      setTranscription(finalTranscript + interim)
      setIsTranscribing(true)
    }

    recognition.onerror = (event: any) => {
      console.warn('Speech recognition error:', event.error)
      if (event.error === 'no-speech') {
        // Restart
        try { recognition.start() } catch (_) {}
      }
    }

    recognition.onend = () => {
      setIsTranscribing(false)
      // Restart if still recording
      if (isRecording) {
        try { recognition.start() } catch (_) {}
      }
    }

    recognition.start()
    recognitionRef.current = recognition
    setIsTranscribing(true)
  }

  function stopSpeechRecognition() {
    if (recognitionRef.current) {
      try { recognitionRef.current.stop() } catch (_) {}
      recognitionRef.current = null
    }
    setIsTranscribing(false)
  }

  // Recording
  function startCountdownThenRecord() {
    setCountdown(3)
    let count = 3
    const interval = setInterval(() => {
      count--
      if (count <= 0) {
        clearInterval(interval)
        setCountdown(null)
        startRecording()
      } else {
        setCountdown(count)
      }
    }, 1000)
  }

  function startRecording() {
    if (!streamRef.current) return

    setIsRecording(true)
    setRecordingTime(0)
    setTranscription('')
    setCapturedFrames([])
    setRecordingDone(false)

    // Start timer
    timerRef.current = setInterval(() => {
      setRecordingTime(prev => prev + 1)
    }, 1000)

    // Start frame capture (every 4 seconds)
    frameIntervalRef.current = setInterval(() => {
      const frame = captureFrame()
      if (frame) {
        setCapturedFrames(prev => [...prev, frame])
      }
    }, 4000)

    // Capture first frame immediately
    setTimeout(() => {
      const frame = captureFrame()
      if (frame) setCapturedFrames(prev => [...prev, frame])
    }, 500)

    // Start speech recognition
    startSpeechRecognition()
  }

  function stopRecording() {
    setIsRecording(false)

    if (timerRef.current) {
      clearInterval(timerRef.current)
      timerRef.current = null
    }

    if (frameIntervalRef.current) {
      clearInterval(frameIntervalRef.current)
      frameIntervalRef.current = null
    }

    // Capture final frame
    const frame = captureFrame()
    if (frame) setCapturedFrames(prev => [...prev, frame])

    stopSpeechRecognition()
    setRecordingDone(true)
  }

  // Submit video response
  async function submitVideoResponse() {
    if (!practiceQuestion) return

    const finalTranscription = transcription.trim()
    if (finalTranscription.length < 20) {
      alert('Your response was too short. Please try recording again and speak for at least 15-20 seconds.')
      return
    }

    if (capturedFrames.length === 0) {
      alert('No video frames were captured. Please try again with camera enabled.')
      return
    }

    setSubmitting(true)
    try {
      const res = await apiCall<{ success: boolean; coaching: VideoCoaching }>('/interviews/practice/submit-video', {
        method: 'POST',
        body: {
          question_id: practiceQuestion.id,
          question: practiceQuestion.question,
          category: practiceQuestion.category,
          transcription: finalTranscription,
          frames: capturedFrames,
          duration_seconds: recordingTime,
        },
      })

      if (res.success) {
        setCoaching(res.coaching)
        stopCamera()
        loadStats()
        loadQuestions()
        loadProgress()
      }
    } catch (err: any) {
      alert(err.message || 'Failed to get AI coaching. Please try again.')
    } finally {
      setSubmitting(false)
    }
  }

